// Parse the OpenRouter LLM response into structured cluster objects
const response = $input.item.json;
const maxPostId = $input.item.json.max_post_id || 0;

let clusters = [];

try {
  // Extract content from OpenAI-compatible response format
  const rawContent = response.choices?.[0]?.message?.content || '';

  // Strip markdown code fences if present
  let cleaned = rawContent.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }

  clusters = JSON.parse(cleaned);

  if (!Array.isArray(clusters)) {
    clusters = [clusters];
  }
} catch (e) {
  // Fallback: if LLM returned garbage, create a single generic cluster
  clusters = [{
    topic_name: 'Uncategorized Discussion',
    category: 'Other',
    summary: 'Posts could not be automatically categorized. Manual review recommended.',
    risk_level: 'LOW',
    trend_score: 10,
    post_ids: []
  }];
}

// Emit each cluster as a separate item for downstream DB upsert
return clusters.map(c => ({
  json: {
    topic_name: (c.topic_name || 'Unknown').substring(0, 255),
    category: c.category || 'Other',
    summary: c.summary || '',
    risk_level: ['LOW','MEDIUM','HIGH','CRITICAL'].includes(c.risk_level) ? c.risk_level : 'LOW',
    trend_score: Math.min(Math.max(parseInt(c.trend_score) || 0, 0), 100),
    is_active: true,
    max_post_id: maxPostId,
    engagement_score: $input.item.json.total_engagement || 0
  }
}));
